//# A Priority Encoder

// Takes in a bitmask of multiple requests and returns the zero-based index of
// the set request bit with the highest priority. The least-significant bit
// has highest priority. If no request bits are set, the output is zero, but
// signalled as invalid.  This Priority Encoder is very closely related to the
// [Number of Trailing Zeros](./Number_of_Trailing_Zeros.html) module. 

// For example:

// * 11111 --> 00000 (0)
// * 00010 --> 00001 (1)
// * 01100 --> 00010 (2)
// * 11000 --> 00011 (3)
// * 10000 --> 00011 (4)
// * 00000 --> 00000 (0, invalid)

// The Priority Encoder translates bitmasks to integers, and so can be
// generally used to convert separate physical events into a number for later
// processing or to index into a table, while filtering out multiple
// simultaneous events into only one.

`default_nettype none

module Priority_Encoder
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  wire    [WORD_WIDTH-1:0]    word_out,
    output  reg                         word_out_valid
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        word_out_valid  = 1'b0;
    end

// First, isolate the least-significant 1 bit

    wire [WORD_WIDTH-1:0] lsb_1;

    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (WORD_WIDTH)
    )
    find_lsb_1
    (
        .word_in    (word_in),
        .word_out   (lsb_1)
    );

// A single bit is a power of two, so take its logarithm, which returns its
// zero-based index, which is also the encoded priority.

    wire logarithm_undefined;

    Logarithm_of_Powers_of_Two
    #(
        .WORD_WIDTH             (WORD_WIDTH)
    )
    calc_bit_index
    (
        .one_hot_in             (lsb_1),
        .logarithm_out          (word_out),
        .logarithm_undefined    (logarithm_undefined)
    );

// However, there is a corner case: if the input word is all zero then the
// logarithm output is undefined, and so the output number is zero as if the
// zeroth bit was set, but invalid.

    always @(*) begin
        word_out_valid = (logarithm_undefined == 1'b0);
    end

endmodule

//# A Priority Arbiter

// Returns a one-hot grant bitmask of the least-significant bit set in a word,
// where bit 0 can be viewed as having highest priority. *A grant is held
// until the request is released.*

// The requestors must raise and hold a `requests` bit and wait until the
// corresponding `grant` bit rises to begin their transaction. *Grants are
// calculated combinationally from the requests*, so pipeline as necessary.
// The highest priority pending and unmasked request is granted once the
// currently granted request is released.  The grant remains for as long as
// the request is held without interruption. Requesters can raise or drop
// their requests before their turn comes, but this must be done synchronously
// to the clock.

//## Usage

// A common use-case for an arbiter is to drive a [one-hot
// multiplexer](./Multiplexer_One_Hot.html) to select one of multiple senders
// requesting for one receiver, or one of multiple receivers requesting from
// one sender. This arrangement requires that the requestors can raise and
// hold a `requests` bit, wait until they receive the correspondig `grant` bit
// to begin their transaction, and to drop their `requests` bit only once they
// are done.  This is very similar to a ready/valid handshake, except that the
// transaction cannot be interrupted, else the granted access is lost.

//## Fairness

// **A Priority Arbiter is not fair:** if a higher-priority request happens too
// frequently it will starve lower-priority requests, and if a lower-priority
// request holds its grant too long it will starve higher-priority requests,
// causing priority inversion. To distribute the grants fairly, you need
// a [Round-Robin Arbiter](./Arbiter_Round_Robin.html).

//### Customizations

// To enable the creation of custom fairness adjustments, the `requests_mask`
// input can be used to exclude one or more requests from being granted in the
// current cycle, and must be updated synchronously to the `clock`. The
// `requests_mask` is arbitrary, and if desired can be calculated from the
// current `requests`, the `grant_previous` one-hot output which holds the
// `grant` from the previous clock cycle, and the current one-hot `grant`
// output.

// * Since a grant typically lasts longer than one cycle and won't get granted
// again for several cycles, taking multiple cycles to compute the next
// `requests_mask` is a valid option.
// * The `requests_mask` is applied combinationally to the `requests` input
// and to the internal `grant_previous`, both of which have a combinational
// path to `grant`, so pipeline as necessary. 

// If unused, leave `requests_mask` set to all-ones, and the masking logic
// will optimize away.

`default_nettype none

module Arbiter_Priority
#(
    parameter INPUT_COUNT = 0
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire    [INPUT_COUNT-1:0]   requests,
    input   wire    [INPUT_COUNT-1:0]   requests_mask,  // Set to all-ones if unused.
    output  wire    [INPUT_COUNT-1:0]   grant_previous,
    output  reg     [INPUT_COUNT-1:0]   grant
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};

    initial begin
        grant = INPUT_ZERO;
    end

// First we filter the requests, masking off any externally disabled requestst
// (`requests_mask` bit is 0)

    reg  [INPUT_COUNT-1:0] requests_masked = INPUT_ZERO;

    always @(*) begin
        requests_masked = requests & requests_mask;
    end

// Then, from the remaining requests, we further mask out all but the highest
// priority (lowest bit) set request. This is the new grant candidate.

    wire [INPUT_COUNT-1:0] grant_candidate;
    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (INPUT_COUNT)
    )
    priority_mask
    (
        .word_in    (requests_masked),
        .word_out   (grant_candidate)
    );

// If the request granted on the previous clock cycle is still active, hold it.
// Else, select the current candidate.   

    always @(*) begin
        grant = ((requests & grant_previous) != INPUT_ZERO) ? grant_previous : grant_candidate;
    end

// A grant cannot be interrupted by a higher priority request until the current 
// granted request is released. We need a register to store the current grant 
// for the next clock cycle.

    Register
    #(
        .WORD_WIDTH     (INPUT_COUNT),
        .RESET_VALUE    (INPUT_ZERO)
    )
    previously_granted_request
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (clear),
        .data_in        (grant),
        .data_out       (grant_previous)
    );

endmodule

//# A Round-Robin Arbiter

// Returns a one-hot grant bitmask selected from one of the raised request
// bits in a word, in round-robin order, going from least-significant bit
// (highest priority) to most-significant bit (lowest priority), and back
// around. *A grant is held until the request is released.*

// Unset request bits are skipped, which avoids wasting time. Requests can be
// raised or dropped before their turn comes, but this must be done
// synchronously to the clock. *Grants are calculated combinationally from the
// requests*, so pipeline as necessary. If the `requests_mask` bit
// corresponding to a `requests` bit is zero, then that request cannot be
// granted that cycle. The round-robin always continues from the last granted
// request, even after an idle period of no requests, unless `clear` is
// asserted.

//## Usage

// A common use-case for an arbiter is to drive a [one-hot
// multiplexer](./Multiplexer_One_Hot.html) to select one of multiple senders
// requesting for one receiver, or one of multiple receivers requesting from
// one sender. This arrangement requires that the requestors can raise and
// hold a `requests` bit, wait until they receive the correspondig `grant` bit
// to begin their transaction, and to drop their `requests` bit only once they
// are done.  This is very similar to a ready/valid handshake, except that the
// transaction cannot be interrupted, else the granted access is lost.

//## Fairness

// Here, we implement a "mask method" round-robin arbiter, as described in
// Section 4.2.4, Figure 12 of Matt Weber's [Arbiters: Design Ideas and Coding
// Styles](http://citeseerx.ist.psu.edu/viewdoc/download?doi=10.1.1.86.550&rep=rep1&type=pdf). 

// A round-robin arbiter is commonly used to fairly divide a resource amongst
// multiple requestors, *in proportion to each requestor's activity*, since
// each requestor holds a grant until they lower their request. Idle
// requestors don't use up any of the arbitrated resource. A frequent
// requestor will not obstruct other requestors perpetually.

// However, this round-robin arbiter does not deal with some subtleties of
// fairness. For example, it's possible that under normal operation, one
// requestor ends up placing a request always just before the previous
// requestor finishes. Thus, that new request waits less than the others. One
// solution periodically takes a snapshot of the current pending requests, and
// services all of these requests before refreshing the snapshot.

//### Customizations

// To enable the creation of custom fairness adjustments, the `requests_mask`
// input can be used to exclude one or more requests from being granted in the
// current cycle, and must be updated synchronously to the `clock`. The
// `requests_mask` is arbitrary, and if desired can be calculated from the
// current `requests`, the `grant_previous` one-hot output which always holds
// the last given grant even if the requests are currently all idle, and the
// current one-hot `grant` output.

// * Since a grant typically lasts longer than one cycle and won't get granted
// again for several cycles, taking multiple cycles to compute the next
// `requests_mask` is a valid option.
// * The `requests_mask` is applied combinationally to the `requests` input
// and to the internal `round_robin_mask`, both of which have a combinational
// path to `grant`, so pipeline as necessary. 

// If unused, leave `requests_mask` set to all-ones, and the masking logic
// will optimize away.

`default_nettype none

module Arbiter_Round_Robin
#(
    parameter INPUT_COUNT = 0
)
(
    input   wire                        clock,
    input   wire                        clear,

    input   wire    [INPUT_COUNT-1:0]   requests,
    input   wire    [INPUT_COUNT-1:0]   requests_mask,  // Set to all-ones if unused.
    output  wire    [INPUT_COUNT-1:0]   grant_previous,
    output  reg     [INPUT_COUNT-1:0]   grant
);

    localparam ZERO = {INPUT_COUNT{1'b0}};

    initial begin
        grant = ZERO;
    end

// We need to detect if any requests are active: *when all requests go idle,
// we want to remember the last granted request.* Otherwise, that lost state
// means the round-robin restarts from the highest priority request rather
// than the next lower priority request after the last granted request. 

// Always granting the highest priority first after an idle period allows
// a pathological request pattern to cause starvation: all but the highest
// priority request would starve if they keep asserting and de-asserting in
// lock-step after an idle period.

    reg any_requests_active = 1'b0;

    always @(*) begin
        any_requests_active = (requests != ZERO);
    end

// For the same reasons, we need to detect when we leave an idle request
// period so we can, for that cycle, refuse to grant again the last granted
// request, which would otherwise cause starvation of other requests happening
// in lock-step.

    wire out_from_idle;

    Pulse_Generator
    requests_restart
    (
        .clock              (clock),
        .level_in           (any_requests_active),
        .pulse_posedge_out  (out_from_idle),
        // verilator lint_off PINCONNECTEMPTY
        .pulse_negedge_out  (),
        .pulse_anyedge_out  ()
        // verilator lint_on  PINCONNECTEMPTY
    );

// Grant a request in priority order (LSB has higest priority) after applying
// `requests_mask`. This is the base case which starts the round-robin.

    reg [INPUT_COUNT-1:0] requests_masked_priority = ZERO;

    always @(*) begin
        requests_masked_priority = requests & requests_mask;
    end

    wire [INPUT_COUNT-1:0] grant_priority;

    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (INPUT_COUNT)
    )
    priority_grants
    (
        .word_in    (requests_masked_priority),
        .word_out   (grant_priority)
    );

// Mask-off all requests *of equal and higher priority* than the request
// currently granted, from the previous cycle. This masking makes the
// round-robin progress towards lower priority requests as the previously
// granted higher priority requests are released. The `thermometer_mask` must
// be inverted before use.

    wire [INPUT_COUNT-1:0] thermometer_mask;

    Bitmask_Thermometer_to_Rightmost_1_Bit
    #(
        .WORD_WIDTH (INPUT_COUNT)
    )
    grant_mask
    (
        .word_in    (grant_previous),
        .word_out   (thermometer_mask)
    );

    reg [INPUT_COUNT-1:0] round_robin_mask = ZERO;

    always @(*) begin
        round_robin_mask = ~thermometer_mask;
    end

// The `round_robin_mask` excludes the currently granted request, which we
// don't want to interrupt, so we OR the currently granted request bit into
// the `round_robin_mask` so we only mask-off all *higher* priority requests,
// leaving the currently granted request as highest priority.

// **EXCEPTION:** If we are returning from an all-idle request phase, we
// instead zero-out that granted request bit, so the round-robin can resume to
// the next lower priority request based on the `round_robin_mask`, instead of
// possibly re-granting the same request again.

// The `round_robin_mask` is further masked, in the same manner, by the
// `requests_mask` input, which may prevent the granting of some `requests` of
// lower priority after the currently granted request is released.

    reg [INPUT_COUNT-1:0] requests_masked_round_robin   = ZERO;
    reg [INPUT_COUNT-1:0] grant_previous_gated          = ZERO;

    always @(*) begin
        grant_previous_gated        = (out_from_idle == 1'b1) ? ZERO : grant_previous;
        requests_masked_round_robin = requests & (round_robin_mask | grant_previous_gated) & (requests_mask | grant_previous_gated);
    end

// Grant a request in priority order, but from the round-robin masked
// requests, which only contain requests of equal or lower priority to the
// currently granted request, minus any requests further masked by the
// `requests_mask` input.

    wire [INPUT_COUNT-1:0] grant_round_robin;

    Bitmask_Isolate_Rightmost_1_Bit
    #(
        .WORD_WIDTH (INPUT_COUNT)
    )
    round_robin_grants
    (
        .word_in    (requests_masked_round_robin),
        .word_out   (grant_round_robin)
    );

// If no round-robin granted requests remain, then instead grant from the
// priority requests, which starts over the round-robin at the highest
// priority (LSB) request.  This also resets `round_robin_mask`.

    always @(*) begin
        grant = (grant_round_robin == ZERO) ? grant_priority : grant_round_robin; 
    end

// Remember the last granted request so we can compute `round_robin_mask` to
// exclude higher priority requests than the last granted request. If all
// requests go idle, don't update, so we can continue the round-robin from
// where we left off when requests appear again, to avoid starvation of lower
// priority requests.

    Register
    #(
        .WORD_WIDTH     (INPUT_COUNT),
        .RESET_VALUE    (ZERO)
    )
    previously_granted_request
    (
        .clock          (clock),
        .clock_enable   (any_requests_active),
        .clear          (clear),
        .data_in        (grant),
        .data_out       (grant_previous)
    );

endmodule

//# Bitmask: Isolate Rightmost 1 Bit

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits

// Use the following formula to isolate the rightmost 1-bit, producing 0 if
// none (e.g., 01011000 -> 00001000)

// This function can trivially implement a [Priority
// Arbiter](./Arbiter_Priority.html), with the highest priority given to the
// least-significant bit, and is the building block of more complex arbiters.

`default_nettype none

module Bitmask_Isolate_Rightmost_1_Bit
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    always @(*) begin
        word_out = word_in & (-word_in);
    end

endmodule

//# Logarithm of Powers of Two

// Translates a power-of-2 binary value (a one-hot bitmask) into its integer
// base-2 logarithm. For example:

// * log<sub>2</sub>(0001) -> log<sub>2</sub>(2<sup>0</sup>) -> log<sub>2</sub>(1) -> 0
// * log<sub>2</sub>(0010) -> log<sub>2</sub>(2<sup>1</sup>) -> log<sub>2</sub>(2) -> 1
// * log<sub>2</sub>(0100) -> log<sub>2</sub>(2<sup>2</sup>) -> log<sub>2</sub>(4) -> 2
// * log<sub>2</sub>(1000) -> log<sub>2</sub>(2<sup>3</sup>) -> log<sub>2</sub>(8) -> 3

// We can see the logarithm of a power-of-2 is simply the index of the single
// set bit: log<sub>2</sub>(2<sup>set_bit_index</sup>) = set_bit_index.

// If the input is not a power-of-2 (more than one set bit), then this
// implementation will output the bitwise-OR of the logarithm of each set bit
// treated as a power-of-2, which I'm not sure has any use or meaning. To save
// hardware (we'd need a [Population Count](./Population_Count.html) or a pair
// of [priority bitmasks](./Bitmask_Isolate_Rightmost_1_Bit.html)), we don't signal these
// cases.
// Also, this calculation fails if no bits are set, since log<sub>2</sub>(0)
// is undefined, and we cannot output zero as that's a valid logarithm. To
// represent the undefined case, we will set an extra bit to declare the output
// undefined, via a simple NOR-reduction of the input.

// We can't implement using a translation table, as with the
// [Static Address Translator](./Address_Translator_Static.html), since we
// would have to create a table capable of holding all 2<sup>WORD_WIDTH</sup>
// possible values, and that would take a *long* time to synthesize and optimize,
// as well as require a lot of system memory.
// Instead, we precalculate each possible logarithm (one per input bit) and
// gate its value based on whether the corresponding input bit is set. We then
// OR-reduce all these possible logarithms into the final answer. We can use
// this implementation method since the amount of logic scales linearly with
// WORD_WIDTH.

// You can use this module to implement unsigned division by powers-of-2 by
// shifting right by the logarithm value. However, *signed* division by
// powers-of-2 has a complication. See [Hacker's
// Delight](./reading.html#Warren2013), Section 10-1, "Signed Division by
// a Known Power of 2". 

// When combined with [Bitmask: Isolate Rightmost
// 1 Bit](./Bitmask_Isolate_Rightmost_1_Bit.html), this module forms the basis
// for the very useful Number of Trailing Zeros (ntz) function. Add a [Word
// Reverser](./Word_Reverser.html) and you can compute Number of Leading Zeros
// (nlz).

`default_nettype none

module Logarithm_of_Powers_of_Two
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    one_hot_in,
    output  wire    [WORD_WIDTH-1:0]    logarithm_out,
    output  reg                         logarithm_undefined
);

    localparam WORD_ZERO = {WORD_WIDTH{1'b0}};

    initial begin
        logarithm_undefined = 1'b0;
    end

// To keep the interface clean, logarithm_out has the same WORD_WIDTH as
// one_hot_in. To calculate each possbile logarithm in parallel, we need an
// array of one output word per input bit. But we must use a flat vector here
// instead of an array since we will be passing this vector of words to
// a Word_Reducer module, and we can't pass multidimensional arrays through
// module ports in Verilog-2001. This means you will hit the Verilog vector
// width limit of about a million when WORD_WIDTH reaches about 1024, though
// simulation and synthesis will have become impractically slow long before
// then.

    localparam TOTAL_WIDTH  = WORD_WIDTH * WORD_WIDTH;
    localparam TOTAL_ZERO   = {TOTAL_WIDTH{1'b0}};

    reg [TOTAL_WIDTH-1:0] all_logarithms = TOTAL_ZERO;

// Most of those logarithm output bits remain a constant zero (and so require
// no logic) since representing the value of a binary number up to
// 2<sup>N</sup>-1 require at most log<sub>2</sub>(N) bits. Therefore,
// representing log<sub>2</sub>(2<sup>N</sup>-1) in binary only needs
// log<sub>2</sub>(log<sub>2</sub>(N)) bits, which is a value that grows
// __very__ slowly. Having output bits stuck at zero will raise CAD tool
// warnings, but that's a lot less error-prone than having the enclosing logic
// calculate the required output logarithm bit width.

// This implementation would ultimately fail if the computed logarithm needs
// more bits than a 32-bit Verilog integer. However, as explained above, that
// would require an input value exceeding 2<sup>2<sup>32</sup></sup>-1, which
// is 2<sup>32</sup> bits long. You are not likely to reach this limit.

// So we pre-compute how many bits we will need to represent the logarithm,
// and also create some zero-padding to expand the logarithm back to
// WORD_WIDTH.

    `include "clog2_function.vh"
    localparam LOGARITHM_WIDTH = clog2(WORD_WIDTH);
    localparam PAD_WIDTH = WORD_WIDTH - LOGARITHM_WIDTH;
    localparam PAD = {PAD_WIDTH{1'b0}};

// Then, for each set input bit, put its logarithm (the bit index) into the
// corresponding array word, else put zero. Note how we slice the integer
// logarithm down to the necessary bits and then pad those back up to the
// array word width.

    generate
        genvar i;
        for(i = 0; i < WORD_WIDTH; i = i + 1) begin : per_input_bit
            always @(*) begin
                all_logarithms[WORD_WIDTH*i +: WORD_WIDTH] = (one_hot_in[i] == 1'b1) ? {PAD, i[LOGARITHM_WIDTH-1:0]} : WORD_ZERO;
            end
        end
    endgenerate

// Then, we OR-reduce the array of possible logarithms down to one.

    Word_Reducer
    #(
        .OPERATION  ("OR"),
        .WORD_WIDTH (WORD_WIDTH),
        .WORD_COUNT (WORD_WIDTH)
    )
    combine_logarithms
    (
        .words_in   (all_logarithms),
        .word_out   (logarithm_out)
    );

// Finally, we detect the case where all input bits are zero and the logarithm
// is undefined.

    always @(*) begin
        logarithm_undefined = (one_hot_in == WORD_ZERO);
    end

endmodule

//# Bitmask: Thermometer to Rightmost 1 Bit

// Credit: [Hacker's Delight](./reading.html#Warren2013), Section 2-1: Manipulating Rightmost Bits

// Use the following formula to create a word with 1’s at the positions of the
// rightmost 1-bit and the trailing 0’s in the input, producing all 1’s if no
// 1-bit, and the integer 1 if no trailing 0’s (e.g., 01011000 -> 00001111)

`default_nettype none

module Bitmask_Thermometer_to_Rightmost_1_Bit
#(
    parameter WORD_WIDTH = 0
)
(
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    localparam ONE = {{WORD_WIDTH-1{1'b0}},1'b1};

    always @(*) begin
        word_out = word_in ^ (word_in - ONE);
    end

endmodule

//# Pulse Generator

// Converts a change in `level_in` (an edge) into a pulse lasting one clock
// cycle. **The input edge must be synchronous to the clock.** The pulse
// outputs are combinational: a given pulse is generated in the same cycle as
// the relevant change in signal level.

// A Pulse Generator can eliminate some simple FSMs by converting a condition
// of unknown length into a one-shot event (e.g.: updating a register only
// once when a signal changes for an unknown time). 

`default_nettype none

module Pulse_Generator
(
    input   wire    clock,
    input   wire    level_in,
    output  reg     pulse_posedge_out,
    output  reg     pulse_negedge_out,
    output  reg     pulse_anyedge_out
);

    initial begin
        pulse_posedge_out = 1'b0;
        pulse_negedge_out = 1'b0;
        pulse_anyedge_out = 1'b0;
    end

// Create a version of the input delayed by one cycle. 

    wire level_in_delayed;

    Register
    #(
        .WORD_WIDTH     (1),
        .RESET_VALUE    (1'b0)
    )
    delay
    (
        .clock          (clock),
        .clock_enable   (1'b1),
        .clear          (1'b0),
        .data_in        (level_in),
        .data_out       (level_in_delayed)
    );

// When the input changes before its delayed version, immediately raise the
// relevant output.  On the next clock cycle, the delayed version will arrive
// and the raised output will go back low.

    always @(*) begin
        pulse_posedge_out = (level_in          == 1'b1) && (level_in_delayed  == 1'b0);
        pulse_negedge_out = (level_in          == 1'b0) && (level_in_delayed  == 1'b1);
        pulse_anyedge_out = (pulse_posedge_out == 1'b1) || (pulse_negedge_out == 1'b1);
    end

endmodule

